import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.TypeAdapterFactory;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class TreeTypeAdapterTest {

  @Test
  public void testNewTypeHierarchyFactory() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    Class<?> hierarchyType = String.class;
    Object typeAdapter = new Object();

    // Call the static method directly
    TypeAdapterFactory factory = TreeTypeAdapter.newTypeHierarchyFactory(hierarchyType, typeAdapter);

    assertNotNull(factory);

    // Use reflection to verify that the returned instance is of type SingleTypeFactory
    Class<?> factoryClass = factory.getClass();
    assertEquals("com.google.gson.internal.bind.TreeTypeAdapter$SingleTypeFactory", factoryClass.getName());

    // Verify fields of SingleTypeFactory via reflection
    var typeAdapterField = factoryClass.getDeclaredField("typeAdapter");
    typeAdapterField.setAccessible(true);
    Object actualTypeAdapter = typeAdapterField.get(factory);
    assertSame(typeAdapter, actualTypeAdapter);

    var hierarchyTypeField = factoryClass.getDeclaredField("hierarchyType");
    hierarchyTypeField.setAccessible(true);
    Object actualHierarchyType = hierarchyTypeField.get(factory);
    assertSame(hierarchyType, actualHierarchyType);

    var matchRawTypeField = factoryClass.getDeclaredField("matchRawType");
    matchRawTypeField.setAccessible(true);
    boolean matchRawType = matchRawTypeField.getBoolean(factory);
    assertFalse(matchRawType);

    var isHierarchyTypeField = factoryClass.getDeclaredField("isHierarchyType");
    isHierarchyTypeField.setAccessible(true);
    // This field might not exist or be named differently; if it does not exist, skip
    // (Based on provided info, only these fields are asserted)

    // Verify toString or other method if needed
    Method toStringMethod = factoryClass.getDeclaredMethod("toString");
    String toStringResult = (String) toStringMethod.invoke(factory);
    assertNotNull(toStringResult);
  }
}
